    "sub_category_uuid": "123e4567-e89b-12d3-a456-426614174111",
    "active": true,
    "trashed": "with",
    "search": "cleaning",
    "per_page": 15
};

fetch(url, {
    method: "GET",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

